#include <assert.h>
#include <stdio.h>
#include <stdlib.h>
#include <math.h>
#include <stdint.h>
#include <chrono>
#include <cuda_runtime.h>

#define MAX_MASK_WIDTH 10
#define MAX_BLOCK_SIZE 1024

#define CUDA_CHECK(call)                                                         \
  do {                                                                           \
    cudaError_t _e = (call);                                                     \
    if (_e != cudaSuccess) {                                                     \
      fprintf(stderr, "CUDA error %s:%d: %s\n", __FILE__, __LINE__,             \
              cudaGetErrorString(_e));                                           \
      exit(1);                                                                   \
    }                                                                            \
  } while (0)

template <typename T, int BLOCK_SIZE>
__global__ void conv1d_kernel(const T *__restrict__ mask,
                              const T *__restrict__ in,
                              T *__restrict__ out,
                              const int input_width,
                              const int mask_width) {
  int i = blockIdx.x * blockDim.x + threadIdx.x;
  if (i < input_width) {
    int start = i - mask_width / 2;
    T s = 0;
    for (int j = 0; j < mask_width; j++) {
      if (start + j >= 0 && start + j < input_width) {
        s += in[start + j] * mask[j];
      }
    }
    out[i] = s;
  }
}

template <typename T, int BLOCK_SIZE>
__global__ void conv1d_tiled_kernel(const T *__restrict__ mask,
                                    const T *__restrict__ in,
                                    T *__restrict__ out,
                                    const int input_width,
                                    const int mask_width) {
  __shared__ T tile[BLOCK_SIZE + MAX_MASK_WIDTH - 1];

  int bid = blockIdx.x;
  int lid = threadIdx.x;
  int dim = blockDim.x;
  int i = bid * dim + lid;

  int n = mask_width / 2;

  int halo_left = (bid - 1) * dim + lid;
  if (lid >= dim - n) {
    tile[lid - (dim - n)] = halo_left < 0 ? (T)0 : in[halo_left];
  }

  tile[n + lid] = (i < input_width) ? in[i] : (T)0;

  int halo_right = (bid + 1) * dim + lid;
  if (lid < n) {
    tile[lid + dim + n] = halo_right >= input_width ? (T)0 : in[halo_right];
  }

  __syncthreads();

  T s = 0;
  for (int j = 0; j < mask_width; j++) {
    s += tile[lid + j] * mask[j];
  }

  if (i < input_width) out[i] = s;
}

template <typename T, int BLOCK_SIZE>
__global__ void conv1d_tiled_caching_kernel(const T *__restrict__ mask,
                                            const T *__restrict__ in,
                                            T *__restrict__ out,
                                            const int input_width,
                                            const int mask_width) {
  __shared__ T tile[BLOCK_SIZE];

  int bid = blockIdx.x;
  int lid = threadIdx.x;
  int dim = blockDim.x;
  int i = bid * dim + lid;

  tile[lid] = (i < input_width) ? in[i] : (T)0;
  __syncthreads();

  int this_tile_start = bid * dim;
  int next_tile_start = (bid + 1) * dim;
  int start = i - (mask_width / 2);
  T s = 0;
  for (int j = 0; j < mask_width; j++) {
    int in_index = start + j;
    if (in_index >= 0 && in_index < input_width) {
      if (in_index >= this_tile_start && in_index < next_tile_start) {
        s += tile[lid + j - (mask_width / 2)] * mask[j];
      } else {
        s += in[in_index] * mask[j];
      }
    }
  }

  if (i < input_width) out[i] = s;
}

template <typename T>
void reference(const T *h_in,
               const T *d_out,
               const T *mask,
               const int input_width,
               const int mask_width) {
  bool ok = true;
  for (int i = 0; i < input_width; i++) {
    T s = 0;
    int start = i - mask_width / 2;
    for (int j = 0; j < mask_width; j++) {
      if (start + j >= 0 && start + j < input_width) {
        s += h_in[start + j] * mask[j];
      }
    }
    if (fabs((double)(s - d_out[i])) > 1e-3) {
      ok = false;
      break;
    }
  }
  printf("%s\n", ok ? "PASS" : "FAIL");
}

template <typename T, int BS>
void launch_conv1d(const T *d_mask, const T *d_in, T *d_out, int input_width, int mask_width) {
  int blocks = (input_width + BS - 1) / BS;
  conv1d_kernel<T, BS><<<blocks, BS>>>(d_mask, d_in, d_out, input_width, mask_width);
}

template <typename T, int BS>
void launch_conv1d_tiled(const T *d_mask, const T *d_in, T *d_out, int input_width, int mask_width) {
  int blocks = input_width / BS;
  conv1d_tiled_kernel<T, BS><<<blocks, BS>>>(d_mask, d_in, d_out, input_width, mask_width);
}

template <typename T, int BS>
void launch_conv1d_tiled_caching(const T *d_mask, const T *d_in, T *d_out, int input_width, int mask_width) {
  int blocks = input_width / BS;
  conv1d_tiled_caching_kernel<T, BS><<<blocks, BS>>>(d_mask, d_in, d_out, input_width, mask_width);
}

template <typename T>
void conv1D(const int input_width, const int mask_width, const int repeat) {
  size_t size_bytes = input_width * sizeof(T);

  T *a = (T *)malloc(size_bytes);
  T *b = (T *)malloc(size_bytes);
  T mask[MAX_MASK_WIDTH];

  for (int i = 0; i < MAX_MASK_WIDTH; i++) mask[i] = 1;

  srand(123);
  for (int i = 0; i < input_width; i++) {
    a[i] = (T)(rand() % 256);
  }

  T *d_a = nullptr, *d_b = nullptr, *d_mask = nullptr;
  CUDA_CHECK(cudaMalloc(&d_a, size_bytes));
  CUDA_CHECK(cudaMalloc(&d_b, size_bytes));
  CUDA_CHECK(cudaMalloc(&d_mask, mask_width * sizeof(T)));

  CUDA_CHECK(cudaMemcpy(d_a, a, size_bytes, cudaMemcpyHostToDevice));
  CUDA_CHECK(cudaMemcpy(d_mask, mask, mask_width * sizeof(T), cudaMemcpyHostToDevice));

  for (int bs = 64; bs <= MAX_BLOCK_SIZE; bs = bs * 2) {
    auto start = std::chrono::steady_clock::now();
    for (int i = 0; i < repeat; i++) {
      switch (bs) {
        case 64:   launch_conv1d<T, 64>(d_mask, d_a, d_b, input_width, mask_width); break;
        case 128:  launch_conv1d<T, 128>(d_mask, d_a, d_b, input_width, mask_width); break;
        case 256:  launch_conv1d<T, 256>(d_mask, d_a, d_b, input_width, mask_width); break;
        case 512:  launch_conv1d<T, 512>(d_mask, d_a, d_b, input_width, mask_width); break;
        case 1024: launch_conv1d<T, 1024>(d_mask, d_a, d_b, input_width, mask_width); break;
      }
    }
    CUDA_CHECK(cudaDeviceSynchronize());
    auto end = std::chrono::steady_clock::now();
    auto time = std::chrono::duration_cast<std::chrono::nanoseconds>(end - start).count();
    printf("Average kernel execution time of conv1d kernel: %f (us)\n",
           (time * 1e-3f) / repeat);
    CUDA_CHECK(cudaMemcpy(b, d_b, size_bytes, cudaMemcpyDeviceToHost));
    reference(a, b, mask, input_width, mask_width);
  }

  for (int bs = 64; bs <= MAX_BLOCK_SIZE; bs = bs * 2) {
    auto start = std::chrono::steady_clock::now();
    for (int i = 0; i < repeat; i++) {
      switch (bs) {
        case 64:   launch_conv1d_tiled<T, 64>(d_mask, d_a, d_b, input_width, mask_width); break;
        case 128:  launch_conv1d_tiled<T, 128>(d_mask, d_a, d_b, input_width, mask_width); break;
        case 256:  launch_conv1d_tiled<T, 256>(d_mask, d_a, d_b, input_width, mask_width); break;
        case 512:  launch_conv1d_tiled<T, 512>(d_mask, d_a, d_b, input_width, mask_width); break;
        case 1024: launch_conv1d_tiled<T, 1024>(d_mask, d_a, d_b, input_width, mask_width); break;
      }
    }
    CUDA_CHECK(cudaDeviceSynchronize());
    auto end = std::chrono::steady_clock::now();
    auto time = std::chrono::duration_cast<std::chrono::nanoseconds>(end - start).count();
    printf("Average kernel execution time of conv1d-tiled kernel: %f (us)\n",
           (time * 1e-3f) / repeat);
    CUDA_CHECK(cudaMemcpy(b, d_b, size_bytes, cudaMemcpyDeviceToHost));
    reference(a, b, mask, input_width, mask_width);
  }

  for (int bs = 64; bs <= MAX_BLOCK_SIZE; bs = bs * 2) {
    auto start = std::chrono::steady_clock::now();
    for (int i = 0; i < repeat; i++) {
      switch (bs) {
        case 64:   launch_conv1d_tiled_caching<T, 64>(d_mask, d_a, d_b, input_width, mask_width); break;
        case 128:  launch_conv1d_tiled_caching<T, 128>(d_mask, d_a, d_b, input_width, mask_width); break;
        case 256:  launch_conv1d_tiled_caching<T, 256>(d_mask, d_a, d_b, input_width, mask_width); break;
        case 512:  launch_conv1d_tiled_caching<T, 512>(d_mask, d_a, d_b, input_width, mask_width); break;
        case 1024: launch_conv1d_tiled_caching<T, 1024>(d_mask, d_a, d_b, input_width, mask_width); break;
      }
    }
    CUDA_CHECK(cudaDeviceSynchronize());
    auto end = std::chrono::steady_clock::now();
    auto time = std::chrono::duration_cast<std::chrono::nanoseconds>(end - start).count();
    printf("Average kernel execution time of conv1d-tiled-caching kernel: %f (us)\n",
           (time * 1e-3f) / repeat);
    CUDA_CHECK(cudaMemcpy(b, d_b, size_bytes, cudaMemcpyDeviceToHost));
    reference(a, b, mask, input_width, mask_width);
  }

  CUDA_CHECK(cudaFree(d_a));
  CUDA_CHECK(cudaFree(d_b));
  CUDA_CHECK(cudaFree(d_mask));

  free(a);
  free(b);
}

int main(int argc, char *argv[]) {
  if (argc != 3) {
    printf("Usage: %s <input_width> <repeat>\n", argv[0]);
    return 1;
  }

  int input_width = atoi(argv[1]);
  input_width = (input_width + MAX_BLOCK_SIZE - 1) / MAX_BLOCK_SIZE * MAX_BLOCK_SIZE;

  const int repeat = atoi(argv[2]);

  for (int mask_width = 3; mask_width < MAX_MASK_WIDTH; mask_width += 2) {
    printf("\n---------------------\n");
    printf("Mask width: %d\n", mask_width);

    printf("1D convolution (FP64)\n");
    conv1D<double>(input_width, mask_width, repeat);

    printf("1D convolution (FP32)\n");
    conv1D<float>(input_width, mask_width, repeat);

    printf("1D convolution (INT16)\n");
    conv1D<int16_t>(input_width, mask_width, repeat);
  }

  return 0;
}
